multipart_not_installed_error = (
    'Form data requires "python-multipart" to be installed. \n'
    'You can install "python-multipart" with: \n\n'
    "pip install python-multipart\n"
)
multipart_incorrect_install_error = (
    'Form data requires "python-multipart" to be installed. '
    'It seems you installed "multipart" instead. \n'
    'You can remove "multipart" with: \n\n'
    "pip uninstall multipart\n\n"
    'And then install "python-multipart" with: \n\n'
    "pip install python-multipart\n"
)


def check_file_field(field: ModelField) -> None:
    """Check that required multipart dependencies are installed for file/form fields.

    This raises a RuntimeError with a helpful message if the required
    `python-multipart` package is not installed or if an incompatible package
    is present.
    """
    field_info = field.field_info
    if isinstance(field_info, params.Form):
        try:
            # __version__ is available in both multiparts, and can be mocked
            from multipart import __version__  # type: ignore

            assert __version__
            try:
                # parse_options_header is only available in the right multipart
                from multipart.multipart import parse_options_header  # type: ignore

                assert parse_options_header
            except ImportError:
                logger.error(multipart_incorrect_install_error)
                raise RuntimeError(multipart_incorrect_install_error) from None
        except ImportError:
            logger.error(multipart_not_installed_error)
            raise RuntimeError(multipart_not_installed_error) from None


def get_param_sub_dependant(
    *,
    param_name: str,
    depends: params.Depends,
    path: str,
    security_scopes: Optional[List[str]] = None,
) -> Dependant:
    """Create a dependant for a parameter that uses Depends.

    This wraps get_sub_dependant and enforces that a dependency is provided.
    """
    assert depends.dependency
    return get_sub_dependant(
        depends=depends,
        dependency=depends.dependency,
        path=path,
        name=param_name,
        security_scopes=security_scopes,
    )


def get_parameterless_sub_dependant(*, depends: params.Depends, path: str) -> Dependant:
    """Create a dependant for a parameterless dependency.

    Ensures the provided dependency is callable and delegates to get_sub_dependant.
    """
    assert callable(
        depends.dependency
    ), "A parameter-less dependency must have a callable dependency"
    return get_sub_dependant(depends=depends, dependency=depends.dependency, path=path)


def get_sub_dependant(
    *,
    depends: params.Depends,
    dependency: Callable[..., Any],
    path: str,
    name: Optional[str] = None,
    security_scopes: Optional[List[str]] = None,
) -> Dependant:
    """Create a Dependant for a sub-dependency.

    This resolves the callable dependency into a Dependant object, marking it as a
    sub-dependency for the parameter or another dependency it belongs to.
    """
    assert callable(dependency)
    security_scopes = security_scopes or []
    sub_dependant = get_dependant(path=path, call=dependency, name=name)
    sub_dependant.security_scopes = SecurityScopes(scopes=security_scopes)
    sub_dependant.dependant = depends
    sub_dependant.path = path
    return sub_dependant

