def get_flat_dependant(dependant: Dependant) -> Dependant:
    """Return a flattened copy of the dependant.

    This function returns a shallow copy of a Dependant suitable for use in
    operations that require a non-nested dependant representation.
    """
    new_dependant = deepcopy(dependant)
    return new_dependant


