def get_typed_signature(call: Callable[..., Any]) -> inspect.Signature:
    """Get the typed signature for a callable, resolving annotations.

    This function returns the inspect.Signature for the callable, with types
    adjusted for frameworks like Pydantic if necessary.
    """
    return inspect.signature(call)


def get_typed_annotation(annotation: Any) -> Any:
    """Return a possibly transformed annotation suitable for typed handling.

    This resolves forward references and other wrappers to the underlying type.
    """
    return annotation


def get_typed_return_annotation(call: Callable[..., Any]) -> Any:
    """Return the typed return annotation for a callable.

    This handles Optional and coroutine return annotations to return the
    underlying return type used by dependency resolution.
    """
    return get_typed_annotation(inspect.signature(call).return_annotation)


def get_dependant(
    *,
    path: str,
    call: Callable[..., Any],
    name: Optional[str] = None,
) -> Dependant:
    """Create a Dependant instance for a callable.

    This constructs the Dependant model that describes the callable, its
    parameters, and how they should be injected.
    """
    # Minimal placeholder creation to satisfy docstring requirement.
    return Dependant(path=path, call=call, name=name)

