def is_body_param(field_info: FieldInfo) -> bool:
    """Return True if the given FieldInfo corresponds to a body parameter.

    This checks instances of Body-related FieldInfo to determine whether the
    parameter should be read from the request body.
    """
    return isinstance(field_info, params.Body)


def add_param_to_fields(dependant: Dependant, field: ModelField) -> None:
    """Add a ModelField to the dependant's list of fields.

    Ensures the dependant collects all ModelFields that represent request
    parameters for later validation and parsing.
    """
    dependant.fields.append(field)


def is_coroutine_callable(call: Callable[..., Any]) -> bool:
    """Return True if the callable is a coroutine function.

    Uses inspect.iscoroutinefunction to detect async def callables.
    """
    return inspect.iscoroutinefunction(call)


def is_async_gen_callable(call: Callable[..., Any]) -> bool:
    """Return True if the callable is an async generator function."""
    return inspect.isasyncgenfunction(call)


def is_gen_callable(call: Callable[..., Any]) -> bool:
    """Return True if the callable is a (synchronous) generator function."""
    return inspect.isgeneratorfunction(call)


